import { useState } from 'react'
import slugify from 'slugify'
import { type Tool, useAppStore } from './store'
import Link from './Link'
import ToolFigure from './ToolFigure'
import Markdown from 'react-markdown'
import remarkGfm from 'remark-gfm'
import styles from './ToolCard.module.css'

function ellipses(f = '', n = 40) {
  return f.slice(0, n) + (f.length > n ? '...' : '')
}

export default function ToolCard({ tool }: { tool: Tool }) {
  const {
    name,
    url,
    language,
    tags,
    img,
    width,
    height,
    github,
    twitter,
    platform,
    github_stars,
    pub,
    note,
    alt_url,
    interactive,
  } = tool
  const store = useAppStore()
  const { filters } = store
  const [expanded, setExpanded] = useState(false)
  const slug = slugify(name, { remove: /[!"'()*+.:@~]/g })
  return (
    <div className={styles.container}>
      <div className={styles.content}>
        <h3 className={styles.title}>
          <Link
            id={slug}
            href="#"
            onClick={event => {
              store.setSelected(`#${slug}`)
              event.preventDefault()
            }}
          >
            {name}
          </Link>
        </h3>
        {url ? (
          <p className={styles.text}>
            <Link href={url}>{ellipses(url)}</Link>
          </p>
        ) : null}
        {alt_url ? (
          <p className={styles.text}>
            Alt url <Link href={alt_url}>{ellipses(alt_url)}</Link>
          </p>
        ) : null}
        {interactive ? (
          <p className={`${styles.text} ${styles.interactive}`}>Interactive: {interactive.join(',')}</p>
        ) : null}
        {pub ? (
          <p className={styles.metadata}>
            Publication:{' '}
            {pub.doi ? (
              <Link
                href={
                  pub.doi.startsWith('http')
                    ? pub.doi
                    : `https://dx.doi.org/${pub.doi}`
                }
              >
                (doi link)
              </Link>
            ) : null}{' '}
            {pub.year ? ` (${pub.year})` : null}
            {pub.citations === undefined
              ? null
              : ` (# citations ${pub.citations})`}
          </p>
        ) : null}
        {language ? (
          <p className={styles.metadata}>
            Language:{' '}
            {language.map((language, index) => [
              index > 0 && ', ',
              <Link
                href="#"
                key={`${language}-${index}`}
                onClick={event => {
                  store.setFilters({ ...filters, language })
                  event.preventDefault()
                }}
              >
                {language}
              </Link>,
            ])}
          </p>
        ) : null}
        {tags ? (
          <p className={styles.metadata}>
            Tags:{' '}
            {tags.map((tag, index) => [
              index > 0 && ', ',
              <Link
                href="#"
                key={`${tag}-${index}`}
                onClick={event => {
                  store.setFilters({ ...filters, tag })
                  event.preventDefault()
                }}
              >
                {tag}
              </Link>,
            ])}
          </p>
        ) : null}
        {note ? (
          <div>
            <Markdown
              remarkPlugins={[remarkGfm]}
              components={{
                a: ({ href, children, ...props }) => (
                  <a href={href} className="link" {...props}>
                    {children}
                  </a>
                ),
              }}
            >
              {'Note: ' + note}
            </Markdown>
          </div>
        ) : null}
        {twitter ? (
          <p className={styles.metadata}>
            Twitter: <Link href={twitter}>{twitter}</Link>
          </p>
        ) : null}
        {github ? (
          <p className={styles.metadata}>
            Github: <Link href={github}>{github}</Link>
          </p>
        ) : null}

        {github_stars ? <p className={styles.metadata}>Github Stargazers: {github_stars}</p> : null}
        {platform ? <p className={styles.metadata}>Platform: {platform.join(', ')}</p> : null}
      </div>
      <ToolFigure
        img={img}
        name={name}
        width={width}
        height={height}
        expanded={expanded}
        setExpanded={setExpanded}
      />
    </div>
  )
}
